import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Avatar, Button, icon } from 'decantr/components';

code.example:
function VersionHistorySidebar({ versions, currentVersionId, onSelect, onRestore, onClose }) {
  const { div, span, time, h3, button } = tags;
  const [selectedId, setSelectedId] = createSignal(currentVersionId);

  const groupByDate = (versions) => {
    const groups = {};
    versions.forEach(v => {
      const date = new Date(v.timestamp).toLocaleDateString();
      (groups[date] = groups[date] || []).push(v);
    });
    return groups;
  };

  const grouped = groupByDate(versions);

  return div({ class: css('_flex _col _hfull _bg[var(--surface)]') },
    // Header
    div({ class: css('_flex _aic _jcsb _p4 _borderB') },
      h3({ class: css('_fontmedium') }, 'Version history'),
      Button({ variant: 'ghost', size: 'sm', onclick: onClose }, icon('x'))
    ),
    // Timeline
    div({ class: css('_flex1 _overflow[auto] _p4') },
      ...Object.entries(grouped).map(([date, dayVersions]) =>
        div({ class: css('_mb4') },
          span({ class: css('_textxs _fgmuted _fontmedium _uppercase') }, date),
          div({ class: css('_flex _col _gap1 _mt2 _borderL2 _border[var(--border)] _ml2') },
            ...dayVersions.map(version =>
              button({
                class: css(`_flex _aic _gap3 _p3 _ml[-9px] _r1 _textleft _wfull _trans ${selectedId() === version.id ? '_bg[var(--primary)/10]' : '_hover:bg[var(--surface-raised)]'}`),
                onclick: () => { setSelectedId(version.id); onSelect(version); }
              },
                // Timeline dot
                div({ 
                  class: css(`_w4 _h4 _rfull _shrink0 ${version.isCheckpoint ? '_bg[var(--primary)]' : '_bg[var(--border)]'}`)
                }),
                // Version info
                div({ class: css('_flex _col _flex1 _min-w0') },
                  span({ class: css('_textsm _fontmedium _truncate') },
                    version.name || (version.isCheckpoint ? 'Named checkpoint' : 'Auto-save')
                  ),
                  div({ class: css('_flex _aic _gap2') },
                    Avatar({ src: version.author.avatar, size: 'xs' }),
                    span({ class: css('_textxs _fgmuted') }, version.author.name),
                    time({ class: css('_textxs _fgmuted') }, version.relativeTime)
                  )
                ),
                // Checkpoint indicator
                version.isCheckpoint ? icon('bookmark', { size: '14', class: css('_fg[var(--primary)]') }) : null
              )
            )
          )
        )
      )
    ),
    // Actions
    selectedId() !== currentVersionId ? div({ class: css('_p4 _borderT _flex _gap2') },
      Button({ variant: 'outline', class: css('_flex1'), onclick: () => {} },
        icon('git-compare', { size: '14' }), ' Compare'
      ),
      Button({ class: css('_flex1'), onclick: () => onRestore(selectedId()) },
        icon('rotate-ccw', { size: '14' }), ' Restore'
      )
    ) : null
  );
}

