function VersionHistoryModal({ versions, currentVersion, onRestore, onClose }) {
  const { div, span, h2, article, button } = tags;
  const [selectedVersion, setSelectedVersion] = createSignal(versions[0]);
  const [showDiff, setShowDiff] = createSignal(false);

  return div({ class: css('_fixed _inset0 _bg[black/50] _flex _aic _jcc _z[100]') },
    div({ class: css('_bg[var(--surface)] _r2 _shadow _overflow[hidden] _w[90vw] _max-w[1200px] _h[80vh] _flex _col') },
      // Header
      div({ class: css('_flex _aic _jcsb _p4 _borderB') },
        h2({ class: css('_heading4') }, 'Version history'),
        Button({ variant: 'ghost', onclick: onClose }, icon('x'))
      ),
      // Content
      div({ class: css('_grid _grid-cols[300px_1fr] _flex1 _overflow[hidden]') },
        // Timeline
        div({ class: css('_borderR _overflow[auto] _p4') },
          ...versions.map(version =>
            button({
              class: css(`_flex _aic _gap3 _p3 _r1 _textleft _wfull _mb1 ${selectedVersion().id === version.id ? '_bg[var(--primary)/10]' : '_hover:bg[var(--surface-raised)]'}`),
              onclick: () => setSelectedVersion(version)
            },
              Avatar({ src: version.author.avatar, size: 'sm' }),
              div({ class: css('_flex _col _flex1') },
                span({ class: css('_textsm _fontmedium') }, version.name || 'Auto-save'),
                span({ class: css('_textxs _fgmuted') }, `${version.author.name} · ${version.relativeTime}`)
              )
            )
          )
        ),
        // Preview
        div({ class: css('_flex _col _overflow[hidden]') },
          div({ class: css('_flex _aic _jcsb _p4 _borderB') },
            div({ class: css('_flex _aic _gap2') },
              button({
                class: css(`_px3 _py1 _r1 _textsm ${!showDiff() ? '_bg[var(--surface-raised)]' : ''}`),
                onclick: () => setShowDiff(false)
              }, 'Preview'),
              button({
                class: css(`_px3 _py1 _r1 _textsm ${showDiff() ? '_bg[var(--surface-raised)]' : ''}`),
                onclick: () => setShowDiff(true)
              }, 'Changes')
            ),
            div({ class: css('_flex _aic _gap2') },
              Button({ variant: 'outline', size: 'sm' },
                icon('download', { size: '14' }), ' Download'
              ),
              Button({ size: 'sm', onclick: () => onRestore(selectedVersion().id) },
                icon('rotate-ccw', { size: '14' }), ' Restore this version'
              )
            )
          ),
          article({ class: css('_flex1 _overflow[auto] _p6 paper-prose') },
            selectedVersion().content
          )
        )
      )
    )
  );
}

