function CompactVersionSelector({ versions, currentVersionId, onSelect }) {
  const { div, span, button } = tags;
  const [open, setOpen] = createSignal(false);
  const current = versions.find(v => v.id === currentVersionId);

  return div({ class: css('_relative') },
    Button({
      variant: 'outline',
      size: 'sm',
      onclick: () => setOpen(!open())
    },
      icon('history', { size: '14' }),
      ' ',
      current?.name || current?.relativeTime,
      icon('chevron-down', { size: '14' })
    ),
    open() ? div({
      class: css('_absolute _top[100%] _right0 _mt1 _w[200px] _bg[var(--surface)] _shadow _r1 _border _z[50] _max-h[300px] _overflow[auto]')
    },
      ...versions.map(v =>
        button({
          class: css(`_flex _aic _gap2 _p2 _wfull _textleft _textsm _hover:bg[var(--surface-raised)] ${v.id === currentVersionId ? '_bg[var(--primary)/10]' : ''}`),
          onclick: () => { onSelect(v); setOpen(false); }
        },
          v.isCheckpoint ? icon('bookmark', { size: '12', class: css('_fg[var(--primary)]') }) : icon('clock', { size: '12', class: css('_fgmuted') }),
          span({ class: css('_truncate') }, v.name || v.relativeTime)
        )
      )
    ) : null
  );
}

